":root {
  --c21-gold: #b49b57;
  --c21-gold-hover: #9c8548;
  --c21-black: #111111;
  --c21-dark-gray: #333333;
  --c21-light-gray: #f5f5f5;
  --c21-white: #ffffff;
  --c21-border: #e0e0e0;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background-color: var(--c21-light-gray);
  color: var(--c21-dark-gray);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  font-family: 'Arial', sans-serif;
  -webkit-font-smoothing: antialiased;
}

/* Typography */
h1 {
  font-size: 2.2rem;
  font-weight: 700;
  color: var(--c21-black);
  margin-bottom: 0.5rem;
  text-align: center;
  letter-spacing: -0.5px;
}

p.subtitle {
  color: #666;
  text-align: center;
  font-size: 1rem;
  margin-bottom: 3rem;
}

/* Layout */
.container {
  max-width: 800px;
  width: 100%;
  margin: 0 auto;
  padding: 4rem 2rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  flex: 1;
}

/* Logo styling */
.brand-logo {
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-bottom: 2rem;
