"import fs from 'fs';

const key = '3fbd635f92f10c5695df6a7e229ff732';
const url = 'https://www.zonaprop.com.ar/propiedades/clasificado/veclapin-departamento-venta-3-ambientes-con-dependencia-y-58298310.html';
const scraperUrl = `https://api.scraperapi.com/?api_key=${key}&url=${encodeURIComponent(url)}&country_code=ar`;

const resp = await fetch(scraperUrl);
const html = await resp.text();

console.log('HTML LENGTH:', html.length);
console.log('HAS ld+json:', html.includes('ld+json'));
console.log('HAS streetAddress:', html.includes('streetAddress'));
console.log('HAS Permite mascotas:', html.includes('Permite mascotas'));
console.log('HAS measure:', html.includes('"measure"'));
console.log('HAS Expensas:', html.includes('Expensas'));
console.log('HAS avisoInfo:', html.includes('avisoInfo'));

// JSON-LD blocks
const ldMatches = html.match(/<script type="application\/ld\+json">([\s\S]*?)<\/script>/g);
console.log('JSON-LD blocks:', ldMatches ? ldMatches.length : 0);
if (ldMatches) {
  ldMatches.forEach((m, i) => {
    try {
      const jsonStr = m.replace(/<script[^>]*>/, '').replace(/<\/script>/, '');
      const json = JSON.parse(jsonStr);
      if (json.address) console.log('ADDRESS:', json.address);
    } catch(e) {}
  });
}

// Features
const fRegex = /"label"\s*:\s*"([^"]+)"\s*,\s*"measure"\s*:\s*(?:"([^"]+)"|null)\s*,\s*"value"\s*:\s*(?:"([^"]+)"|null)/g;
const feats = [];
let m;
while ((m = fRegex.exec(html)) !== null) feats.push(m[1]);
console.log('FEATURES:', feats.length, feats.slice(0, 5));

// Expensas
const expMatch = html.match(/Expensas\s*\$?\s*[\d\.]+/i);
console.log('EXPENSAS:', expMatch ? expMatch[0] : 'NOT FOUND');
"

