"import fs from 'fs';
const html = fs.readFileSync('zonaprop_test2.html', 'utf8');

// Check all image URL patterns
const imgPatterns = html.match(/https?:\/\/[^\s"']+\.(jpg|jpeg|webp|png)/gi) || [];
const unique = [...new Set(imgPatterns)];

// Categorize by size
const sizes = {};
unique.forEach(u => {
  const sizeMatch = u.match(/(\d+x\d+)/);
  const size = sizeMatch ? sizeMatch[1] : 'no-size';
  if (!sizes[size]) sizes[size] = [];
  sizes[size].push(u);
});

console.log('TOTAL UNIQUE IMAGES:', unique.length);
for (const [size, urls] of Object.entries(sizes)) {
  console.log(`\n${size}: ${urls.length} images`);
  console.log('  SAMPLE:', urls[0].substring(0, 120));
}

// Check for 1200x1200 specifically
const big = unique.filter(u => u.includes('1200x1200'));
console.log('\n1200x1200 count:', big.length);

// Check for 360x266 or other gallery sizes
const gallery = unique.filter(u => u.includes('360x266') || u.includes('800x600') || u.includes('640x480'));
console.log('Gallery sizes:', gallery.length);

// Check for any zonaprop/navent CDN images
const cdn = unique.filter(u => u.includes('img') && (u.includes('zonaprop') || u.includes('navent') || u.includes('tokko') || u.includes('static')));
console.log('CDN images:', cdn.length);
if (cdn.length) console.log('CDN SAMPLE:', cdn[0]);
"

