console.log('Total 1200x1200:', foundImages.length);
foundImages.slice(0, 10).forEach(img => console.log(img));

// Group by filename to see duplicates
const groups = {};
foundImages.forEach(img => {
  const parts = img.split('/');
  const filename = parts[parts.length - 1];
  if (!groups[filename]) groups[filename] = [];
  groups[filename].push(img);
});

console.log('\nDUPLICATES:');
for (const [filename, urls] of Object.entries(groups)) {
  if (urls.length > 1) {
    console.log(`\n${filename} has ${urls.length} versions:`);
    urls.forEach(u => console.log('  ' + u));
  }
}
