"const fs = require('fs');

async function run() {
  try {
    const key = '3fbd635f92f10c5695df6a7e229ff732';
    const listRes = await fetch('https://inmuebles.mercadolibre.com.ar/departamentos/venta/');
    const listHtml = await listRes.text();
    const match = listHtml.match(/https:\/\/inmueble\.mercadolibre\.com\.ar\/MLA-[^"]+/);

    if (match) {
        console.log('FOUND URL:', match[0]);
        const scraperUrl = `https://api.scraperapi.com/?api_key=${key}&url=${encodeURIComponent(match[0])}&country_code=ar`;
        const res = await fetch(scraperUrl);
        const html = await res.text();
        fs.writeFileSync('ml_real.html', html);
        console.log('HTML length:', html.length);
        const titleMatch = html.match(/<title>([^<]+)/);
        console.log('TITLE:', titleMatch ? titleMatch[1] : 'No title');

        // Find price
        const priceMatch = html.match(/<meta itemprop="price" content="([^"]+)"/);
        console.log('PRICE:', priceMatch ? priceMatch[1] : 'No price');

        // Find currency
        const currencyMatch = html.match(/<meta itemprop="priceCurrency" content="([^"]+)"/);
        console.log('CURRENCY:', currencyMatch ? currencyMatch[1] : 'No currency');

        // Check images
        const imagesMatch = html.match(/<figure class="ui-pdp-gallery__figure">([\s\S]*?)<\/figure>/g);
        console.log('GALLERY IMAGES COUNT:', imagesMatch ? imagesMatch.length : 0);

        // check next data or state
        console.log('Has __PRELOADED_STATE__:', html.includes('__PRELOADED_STATE__'));
    } else {
        console.log('No URL found');
    }
  } catch(e) {
    console.error(e);
  }
}

run();"

