  const idx = html.search(p);
  if (idx > -1) {
    console.log(`\n=== PATTERN: ${p} at index ${idx} ===`);
    console.log(html.substring(idx - 100, idx + 200).replace(/<[^>]+>/g, ' ').trim().substring(0, 200));
